const err = $input.first().json;
const msg = err.error?.message || 'Unknown error';
const workflow = err.workflow?.name || 'unknown workflow';

let emoji = '⚠️';
let action = 'Monitor — auto-retry may resolve.';

if (msg.includes('401') || msg.includes('Unauthorized') || msg.includes('auth')) {
  emoji = '🔴';
  action = 'Action required: re-authenticate affected service.';
} else if (msg.includes('connection') || msg.includes('database')) {
  emoji = '🔴';
  action = 'Check Supabase connectivity.';
} else if (msg.includes('timeout')) {
  emoji = '⚠️';
  action = 'Timeout — auto-retry triggered.';
}

const text = `${emoji} ${new Date().toISOString().split('T')[0]} — ${workflow}: ${msg.substring(0, 200)}. Action: ${action}`;
return [{ json: { text } }];

const scripts = $input.all().map(i => i.json);
const cutoff72h = Date.now() - 259200000;
const toReject = scripts.filter(s => new Date(s.created_at).getTime() < cutoff72h);
const toWarn = scripts.filter(s => new Date(s.created_at).getTime() >= cutoff72h);
return [{ json: { to_reject: toReject, to_warn: toWarn } }];

const events = $input.all().map(i => i.json);
const now = Date.now();
const due24h = events.filter(e => e.payload?.poll_at_24h && new Date(e.payload.poll_at_24h).getTime() <= now && !e.payload?.perf_24h_done);
const due72h = events.filter(e => e.payload?.poll_at_72h && new Date(e.payload.poll_at_72h).getTime() <= now && !e.payload?.perf_72h_done);

// For each due poll: fire TikTok Creator API call and update posts table
// In production: these become separate HTTP Request + PATCH nodes in a loop
return [{ json: { due_24h: due24h.length, due_72h: due72h.length, polls: [...due24h.map(e => ({...e, poll_type: '24h'})), ...due72h.map(e => ({...e, poll_type: '72h'}))] } }];

const stuckJobs = $('Check Stuck Video Jobs').all().map(i => i.json);
const stuckPosts = $('Check Stuck Posts').all().map(i => i.json);
const pendingApprovals = $('Check Unanswered Approvals').all().map(i => i.json);
const issues = [];

if (stuckJobs.length > 0) {
  issues.push(`• ${stuckJobs.length} video job(s) stuck >30min: ${stuckJobs.map(j => j.client_id).join(', ')}`);
}
if (stuckPosts.length > 0) {
  issues.push(`• ${stuckPosts.length} post(s) stuck uploading >15min: ${stuckPosts.map(p => p.client_id).join(', ')}`);
}
if (pendingApprovals.length > 0) {
  const old = pendingApprovals.filter(s => Date.now() - new Date(s.created_at).getTime() > 86400000);
  if (old.length > 0) issues.push(`• ${old.length} script(s) awaiting approval >24h: ${[...new Set(old.map(s => s.client_id))].join(', ')}`);
}

const today = new Date().toISOString().split('T')[0];
let text;
if (issues.length === 0) {
  text = `✅ ${today} — All systems healthy. No issues detected.`;
} else {
  text = `📊 ${today} Daily Check — ${issues.length} issue(s):\n${issues.join('\n')}`;
}

return [{ json: { text, has_issues: issues.length > 0 } }];
